module RefModule (CLK, RST, UP_DOWN, COUNT);
input CLK, RST, UP_DOWN;
output reg [2:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
	if (RST)
		COUNT <= 3'b000;
	else if (UP_DOWN)
		COUNT <= COUNT + 1;
	else
		COUNT <= COUNT - 1;
end

endmodule
